/// 可写而不阻塞。
pub(crate) const POLLOUT: i16 = 0x0004;
/// 发生错误条件（始终被 poll 返回，无需在 events 中请求）。
pub(crate) const POLLERR: i16 = 0x0008;
/// 对端挂断/连接关闭。
