fn can_send_signal(
    sender_uid: u32,
    sender_euid: u32,
    sender_sid: usize,
    target_uid: u32,
    target_euid: u32,
    target_suid: u32,
    target_sid: usize,
    signum: i32,
) -> bool {
    if sender_euid == 0 {
        return true;
    }
    if sender_uid == target_uid
        || sender_uid == target_euid
        || sender_uid == target_suid
        || sender_euid == target_uid
        || sender_euid == target_euid
        || sender_euid == target_suid
    {
        return true;
    }
    signum as usize == SIGCONT_NUM && sender_sid != 0 && sender_sid == target_sid
}

